class Solution(object):
    def maximumSumOfHeights(self, maxHeights):
        n = len(maxHeights)
        best = 0
        for peak in range(n):
            total = maxHeights[peak]
            cur = maxHeights[peak]
            for i in range(peak - 1, -1, -1):
                cur = min(cur, maxHeights[i])
                total += cur
            cur = maxHeights[peak]
            for i in range(peak + 1, n):
                cur = min(cur, maxHeights[i])
                total += cur
            best = max(best, total)
        return best
